const r = $input.first().json;
const hour = Number(r.hour_utc);

if (hour < 12 || hour >= 22) {
  return [{ json: { should_alert: false, anomaly: false, reason: 'outside_compare_window', hour, snapshot: r } }];
}
if (Number(r.today_alerts || 0) > 0) {
  return [{ json: { should_alert: false, anomaly: false, reason: 'already_alerted_today', hour, snapshot: r } }];
}

const todayGross   = Number(r.today_gross || 0);
const trailingAvg  = Number(r.gross_avg || 0);
const todayCovers  = Number(r.today_covers || 0);
const coversAvg    = Number(r.covers_avg || 0);
const todayOcc     = r.today_occ == null ? null : Number(r.today_occ);
const occAvg       = Number(r.occ_avg || 0);
const sampleN      = Number(r.sample_n || 0);

const issues = [];

// Only check if we have a reasonable baseline (≥ 2 same-DOW samples)
if (sampleN >= 2 && trailingAvg > 50) {
  const deviation = (todayGross - trailingAvg) / trailingAvg;
  if (deviation < -0.30 && hour >= 14) {
    issues.push({ kind: 'epos_below', deviation: Math.round(deviation * 100), today_gross: todayGross.toFixed(2), avg: trailingAvg.toFixed(2) });
  }
  if (deviation > 0.80) {
    issues.push({ kind: 'epos_spike', deviation: Math.round(deviation * 100), today_gross: todayGross.toFixed(2), avg: trailingAvg.toFixed(2) });
  }
}
if (sampleN >= 2 && coversAvg > 5) {
  const cdev = (todayCovers - coversAvg) / coversAvg;
  if (cdev < -0.40 && hour >= 14) {
    issues.push({ kind: 'covers_below', deviation: Math.round(cdev * 100), today: todayCovers, avg: coversAvg.toFixed(0) });
  }
}
if (todayOcc != null && occAvg > 10) {
  const odev = (todayOcc - occAvg) / occAvg;
  if (odev < -0.40) {
    issues.push({ kind: 'occ_below', deviation: Math.round(odev * 100), today: todayOcc, avg: occAvg.toFixed(1) });
  }
}

return [{ json: { should_alert: issues.length > 0, anomaly: issues.length > 0, issues, hour, snapshot: r } }];

